1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using TicketClassifier.Models;
4. 
5. namespace TicketClassifier.Services;
6. 
7. public class TicketClassifierService
8. {
9.     private readonly MLContext _mlContext;
10.     private readonly string _dataPath;
11.     private readonly string _modelPath;
12.     private ITransformer? _model;
13.     private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
14.     private string[]? _categoryNames;
15. 
16.     public bool IsModelTrained => _model is not null;
17. 
18.     public TicketClassifierService(IWebHostEnvironment env)
19.     {
20.         _mlContext = new MLContext(seed: 0);
21.         _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
22.         _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
23.     }
24. 
25.     public void TrainModel()
26.     {
27.         var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
28.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
29. 
30.         // Combine text features and build the pipeline
31.         var pipeline = _mlContext.Transforms.Conversion
32.                 .MapValueToKey("Label", nameof(TicketData.Category))
33.             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
34.             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
35.             .Append(_mlContext.Transforms.Concatenate("Features",
36.                 "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
37.             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
38.             .AppendCacheCheckpoint(_mlContext)
39.             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
40.                 labelColumnName: "Label", featureColumnName: "Features"))
41.             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
42. 
43.         _model = pipeline.Fit(dataView);
44. 
45.         // Extract category names in the key order used by the model
46.         var transformedData = _model.Transform(dataView);
47.         var scoreColumn = transformedData.Schema["Score"];
