 using Microsoft.ML;
 using Microsoft.ML.Data;
 using TicketClassifier.Models;

 namespace TicketClassifier.Services;

 public class TicketClassifierService
 {
     private readonly MLContext _mlContext;
     private readonly string _dataPath;
     private readonly string _modelPath;
     private ITransformer? _model;
     private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
     private string[]? _categoryNames;

     public bool IsModelTrained => _model is not null;

     public TicketClassifierService(IWebHostEnvironment env)
     {
         _mlContext = new MLContext(seed: 0);
         _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
         _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
     }

     public void TrainModel()
     {
         var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

         // Combine text features and build the pipeline
         var pipeline = _mlContext.Transforms.Conversion
                 .MapValueToKey("Label", nameof(TicketData.Category))
             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
             .Append(_mlContext.Transforms.Concatenate("Features",
                 "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
             .AppendCacheCheckpoint(_mlContext)
             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                 labelColumnName: "Label", featureColumnName: "Features"))
             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

         _model = pipeline.Fit(dataView);

         // Extract category names in the key order used by the model
         var transformedData = _model.Transform(dataView);
         var scoreColumn = transformedData.Schema["Score"];
         var slotNames = new VBuffer<ReadOnlyMemory<char>>();
         scoreColumn.GetSlotNames(ref slotNames);
         _categoryNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

         _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

         _mlContext.Model.Save(_model, dataView.Schema, _modelPath);
     }

     public EvaluationResult Evaluate()
     {
         if (_model is null)
             throw new InvalidOperationException("Model must be trained before evaluation.");

         var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

         // Re-apply label mapping for evaluation
         var labelPipeline = _mlContext.Transforms.Conversion
             .MapValueToKey("Label", nameof(TicketData.Category));
         var labeledData = labelPipeline.Fit(dataView).Transform(dataView);

         var predictions = _model.Transform(labeledData);
         var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

         var result = new EvaluationResult
         {
             MacroAccuracy = metrics.MacroAccuracy,
             MicroAccuracy = metrics.MicroAccuracy,
             LogLoss = metrics.LogLoss,
             LogLossReduction = metrics.LogLossReduction
         };

         for (int i = 0; i < metrics.PerClassLogLoss.Count; i++)
         {
             result.PerCategoryMetrics.Add(new CategoryMetric
             {
                 Category = _categoryNames is not null && i < _categoryNames.Length
                     ? _categoryNames[i]
                     : $"Class {i}",
                 Precision = i < metrics.PerClassLogLoss.Count ? 1.0 - metrics.PerClassLogLoss[i] : 0,
                 Recall = 1.0 - metrics.PerClassLogLoss[i]
             });
         }

         return result;
     }

     public PredictionResult Predict(TicketRequest request)
     {
         if (_predictionEngine is null)
             throw new InvalidOperationException("Model must be trained before prediction.");

         var ticketData = new TicketData
         {
             Subject = request.Subject,
             Description = request.Description,
             Priority = request.Priority
         };

         var prediction = _predictionEngine.Predict(ticketData);

         var result = new PredictionResult
         {
             PredictedCategory = prediction.Category
         };

         if (_categoryNames is not null && prediction.Score.Length == _categoryNames.Length)
         {
             for (int i = 0; i < _categoryNames.Length; i++)
             {
                 result.Confidence[_categoryNames[i]] = prediction.Score[i];
             }
         }

         return result;
     }
 }

